        for (Method m : solClass.getDeclaredMethods()) {
            if (!m.getName().equals("main") && (m.getModifiers() & java.lang.reflect.Modifier.PUBLIC) != 0) {
                targetMethod = m;
                break;
            }
        }

        if (targetMethod == null) {
            System.err.println("Error: Solution method not found");
