                    if (!val.equals("null")) {
                        Object left = tnClass.getDeclaredConstructor(int.class).newInstance(Integer.parseInt(val));
                        tnClass.getField("left").set(curr, left);
                        q.add(left);
                    }
                }
                if (idx < parts.length) {
                    String val = parts[idx++].trim();
                    if (!val.equals("null")) {
