                        line = line.Substring(1, line.Length - 2);
                    }
                    args.Add(line);
                } else {
                    throw;
                }
            }
        }

        var solInstance = Activator.CreateInstance(solutionType);
        object result = method.Invoke(solInstance, args.ToArray());

        if (method.ReturnType != typeof(void)) {
